+    private func makeUsageSubmenu(
+        provider: UsageProvider,
+        snapshot: UsageSnapshot?,
+        webItems: OpenAIWebMenuItems) -> NSMenu?
+    {
+        if provider == .codex, webItems.hasUsageBreakdown {
